VALUES
  ('heelevel3-5ff21eeb-moex-00094', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列那些事項最能說明「特別法優於普通法原則」？①計算所得稅時，需額外考量納稅者權利保', '["納稅義務人逾期繳納營業稅稅款者，應依稅捐稽徵法之規 定課徵滯納金", "解釋函令不得牴觸法律的規定", "一行為同時觸犯刑事法律及違反行政法上 義務規定者，依刑事法律處罰", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00095', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '甲收到稅捐稽徵機關核發補徵111年度房屋稅繳款書，繳納截止日期為113年3月31日（星期日）， 但其延遲至113年4月4日（星期四）繳納應納稅款新臺幣2萬元，試問應加徵多少元滯納金？', '["0元", "200元", "400元", "600元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00096', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '依現行納稅者權利保護法及相關規定，維持基本生活所需之費用，不得加以課稅。納稅者依所得 稅法規定申報綜合所得稅時，申報戶之基本生活所需費用總額超過該戶之免稅額及扣除額部分， 得自其綜合所得總額中減除。上開扣除額不包括下列何者？', '["財產交易損失", "儲蓄投資特別扣除", "身心障礙特別扣除", "幼兒學前特別扣除"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00097', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '依現行所得稅法規定，取得下列何者所得，應計入綜合所得總額合併計稅？①出售上市股票之交', '["公益彩券中獎獎金10萬元", "上市公司配發股票股利1000股1萬元", "本 國銀行美元定期存款利息所得1萬元  ⑤持有公債之利息所得5千元", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00098', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '納稅義務人申報 113 年度綜合所得稅如採用標準扣除額，下列何者無法列入扣除額？①醫藥費', '["儲蓄投資扣除額", "身心障礙扣除額", "房屋租金支出  ⑤捐贈  ⑥財產交易損失  ⑦災害損失", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00099', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '依現行所得稅法規定，下列何項扣除額限納稅義務人本人、配偶、受扶養直系親屬才可適用？', '["保險費", "醫藥費", "房屋租金支出", "身心障礙扣除額  ⑤長期照護扣除額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00100', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列有關營利事業之捐贈，何者無金額限制，得全數認列為當年度費用或損失？①對各級政府之', '["對中小企業發展基金之捐贈", "捐贈各級公立學校興建運動場館設施", "購買由國內 文化創意事業原創之產品，經由學校捐贈學生  ⑤透過財團法人私立學校興學基金會指定對某私 立大學之捐贈", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00101', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '我國甲公司在日本設有分公司，其112年度營利事業課稅所得額為新臺幣1,000萬元，日本分公 司同年度所得折合新臺幣600萬元，已在日本繳納日本分公司所得稅折合新臺幣125萬元，請問 甲公司申報112年度營利事業所得稅時可使用國外稅額扣抵上限為多少元？', '["80萬元", "100萬元", "120萬元", "125萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00102', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '甲公司於112年10月16日開業，會計年度採曆年制，當年度10月16日至12月31日之營利事業 所得額為4萬元，請問112年度全年課稅所得額為多少元？實際應納營利事業所得稅額為多少元？', '["4萬元；0元", "4萬元；0.8萬元", "16萬元；0.5萬元", "16萬元；0.8萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00103', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '地價稅有關自用住宅用地適用條件之相關規定，下列何者正確？①土地所有權人與其配偶及未成', '["無出租、無供營業用之住宅用地", "土地上之建築改良 物屬土地所有權人或其配偶、直系親屬所有", "土地所有權人與其配偶及直系親屬，以1處為限 ⑤都市土地面積未超過3公畝，非都市土地面積未超過7公畝", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
